args.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?eventLabel WHERE {
  ?player wdt:P54 wd:Q1631126 .
  ?player wdt:P31 wd:Q5 .
  ?player wdt:P2048 ?height .
  FILTER(?height >= 1.96 && ?height <= 1.98) .
  { ?player wdt:P179 ?event }
  UNION
  { ?player wdt:P1344 ?event }
  ?event rdfs:label ?eventLabel .
  FILTER(LANG(?eventLabel) = 'en')
}
LIMIT 10
